import React from "react";
//import ReactExport from "react-export-excel";
import ReactExport from "react-data-export";
//import { ExcelFile, ExcelSheet } from "react-export-excel";
import { Button } from "@chakra-ui/react";

const ExcelFile = ReactExport.ExcelFile;
const ExcelSheet = ReactExport.ExcelFile.ExcelSheet;
const ExcelColumn = ReactExport.ExcelFile.ExcelColumn;

const ExportLeave2Excel = ({ filename, dataset, title }) => {
  const cols1 = [
    {
      title: "Findings",
      width: { wch: 68 },
      style: {
        font: { sz: "9", bold: true },
        //fill: { patternType: "solid", fgColor: { rgb: "FF00FF00" } },
        alignment: {
          wrapText: true,
          horizontal: "center",
          vertical: "top",
        },
      },
    },
  ];
  const data1 = [{}];
  const cols = [
    {
      title: "What is/are the findings?",
      width: { wch: 34 },
      style: {
        //font: { sz: "9", bold: true },
        //fill: { patternType: "solid", fgColor: { rgb: "FF00FF00" } },
        alignment: {
          wrapText: true,
          horizontal: "center",
          vertical: "top",
        },
      },
    },
    {
      title: "What is/are the potential hazard(s)/risk(s)?",
      width: { wch: 34 },
      style: {
        //font: { sz: "9", bold: true },
        //fill: { patternType: "solid", fgColor: { rgb: "FF00FF00" } },
        alignment: {
          wrapText: true,
          horizontal: "center",
          vertical: "top",
        },
      },
    },
    {
      title: "Type / Category",
      width: { wch: 14 },
      style: {
        //font: { sz: "9", bold: true },
        //fill: { patternType: "solid", fgColor: { rgb: "FF00FF00" } },
        alignment: {
          wrapText: true,
          horizontal: "center",
          vertical: "top",
        },
      },
    },
    {
      title: "What",
      width: { wch: 18 },
      style: {
        font: { sz: "9", bold: true },
        //fill: { patternType: "solid", fgColor: { rgb: "FF00FF00" } },
        alignment: {
          wrapText: true,
          horizontal: "center",
          vertical: "top",
        },
      },
    },
    {
      title: "What Details",
      width: { wch: 28 },
      style: {
        font: { sz: "9", bold: true },
        fill: { patternType: "solid", fgColor: { rgb: "FF00FF00" } },
        alignment: {
          wrapText: true,
          horizontal: "center",
          vertical: "top",
        },
      },
    },
    {
      title: "Why",
      width: { wch: 18 },
      style: {
        font: { sz: "9", bold: true },
        fill: { patternType: "solid", fgColor: { rgb: "FF00FF00" } },
        alignment: {
          wrapText: true,
          horizontal: "center",
          vertical: "top",
        },
      },
    },
  ];

  const hocdata = dataset.map((rec, index) => {
    return [
      {
        value: rec.findings,
        style: {
          font: { sz: "9" },
          alignment: {
            wrapText: true,
            horizontal: "center",
            vertical: "top",
          },
        },
      },
      {
        value: rec.risks,
        style: {
          font: { sz: "9" },
          alignment: {
            wrapText: true,
            horizontal: "center",
            vertical: "top",
          },
        },
      },
      {
        value: rec.category,
        style: {
          font: { sz: "9" },
          alignment: {
            wrapText: true,
            horizontal: "center",
            vertical: "top",
          },
        },
      },
      {
        value: rec.what,
        // style: {
        //   font: { sz: "9" },
        //   alignment: {
        //     wrapText: true,
        //     horizontal: "center",
        //     vertical: "top",
        //   },
        // },
      },
      {
        value: rec.what_details,
        // style: {
        //   font: { sz: "9" },
        //   alignment: {
        //     wrapText: true,
        //     horizontal: "center",
        //     vertical: "top",
        //   },
        // },
      },
      {
        value: rec.why,
        // style: {
        //   font: { sz: "9" },
        //   alignment: {
        //     wrapText: true,
        //     horizontal: "center",
        //     vertical: "top",
        //   },
        // },
      },
    ];
  });

  

  const multiDataSet = [
    {
      columns: cols1,
      data: [],
    },
    {
      columns: cols,
      data: hocdata,
    },
  ];

  console.log("hocdata", cols, hocdata);
  return (
    // <ExcelFile element={<Button>Export to Excel</Button>} filename={filename}>
    //   <ExcelSheet dataSet={multiDataSet1} name="Organization" />
    // </ExcelFile>

    <ExcelFile element={<Button>Export to Excel</Button>} filename={filename}>
      <ExcelSheet dataSet={multiDataSet} name="HOC" />
    </ExcelFile>

    // <ExcelFile element={<Button>Export to Excel</Button>} filename={filename}>
    //   <ExcelSheet data={dataset} name={title}>
    //     <ExcelColumn label="Name" value="name" />
    //     <ExcelColumn label="From Date" value="from_date" />
    //     <ExcelColumn label="To Date" value="to_date" />
    //     <ExcelColumn label="No of Days" value="no_of_days" />
    //     <ExcelColumn label="Reason" value="reason" />
    //     <ExcelColumn label="Status" value="status" />
    //   </ExcelSheet>
    //</ExcelFile>
  );
};

export default ExportLeave2Excel;
